def sz_attrs(sz, vbox=24):
    if isinstance(vbox, int): vbox = (vbox, vbox)
    if isinstance(sz, int): sz = (sz, sz)
    return dict(viewBox=f'0 0 {vbox[0]} {vbox[1]}', width=f'{sz[0]}px', height=f'{sz[1]}px')
